#[derive(Clone, Copy)]
enum FormulaFallbackSourceKind {
    Enum,
    Color,
    String,
    Trigger,
}

impl FormulaFallbackSourceKind {
    fn label(self) -> &'static str {
        match self {
            Self::Enum => "enum",
            Self::Color => "color",
            Self::String => "string",
            Self::Trigger => "trigger",
        }
    }
}

