fn assert_asset_public_update_target_to_source_bindings_matches_cpp_probe(
    label: &str,
    bytes: Vec<u8>,
    data_bind_indices: &[usize],
) {
    let Some(probe) = probe_path() else {
        eprintln!("skipping C++ runtime comparison; set RIVE_CPP_PROBE to enable");
        return;
    };

    let forced_value = 11_u64;
    let args = [
        "--runtime-bind-default-view-model-state-machine-context".to_owned(),
        "0".to_owned(),
        "--runtime-advance-state-machine".to_owned(),
        "0".to_owned(),
        "0".to_owned(),
        "--runtime-set-state-machine-bindable-asset".to_owned(),
        "0".to_owned(),
        "0".to_owned(),
        forced_value.to_string(),
        "--runtime-update-state-machine-data-binds".to_owned(),
        "0".to_owned(),
        "--runtime-advance-state-machine".to_owned(),
        "0".to_owned(),
        "0".to_owned(),
        "--runtime-advance-state-machine".to_owned(),
        "0".to_owned(),
        "1".to_owned(),
    ];

    let cpp = read_cpp_probe_bytes_with_args(&probe, label, &bytes, &args);
    let (_, mut rust) = read_rust_instance_from_bytes(&bytes, label);
    let mut state_machine = rust
        .state_machine_instance(0)
        .unwrap_or_else(|| panic!("missing Rust state-machine instance for {label}"));

    let mut rust_reports = Vec::new();
    assert!(
        state_machine.bind_default_view_model_context(),
        "{label} failed to bind default view-model context"
    );
    rust_reports.push((
        rust.advance_state_machine_instance(&mut state_machine, 0.0),
        state_machine.clone(),
    ));
    assert!(
        state_machine.set_bindable_asset_for_data_bind(0, forced_value),
        "{label} failed to mutate bindable asset"
    );
    assert!(
        state_machine.update_data_binds_apply_target_to_source(),
        "{label} failed to update data binds"
    );
    rust_reports.push((false, state_machine.clone()));
    rust_reports.push((
        rust.advance_state_machine_instance(&mut state_machine, 0.0),
        state_machine.clone(),
    ));
    rust_reports.push((
        rust.advance_state_machine_instance(&mut state_machine, 1.0),
        state_machine.clone(),
    ));
    let report = rust.update_components();

    let cpp_artboard = cpp
        .artboards
        .first()
        .unwrap_or_else(|| panic!("missing C++ artboard for {label}"));
    assert_eq!(
        cpp_artboard.runtime_state_machine_advances.len(),
        rust_reports.len(),
        "{label} state-machine report count mismatch"
    );
    for (step, (cpp_state_machine, (advanced, rust_state_machine))) in cpp_artboard
        .runtime_state_machine_advances
        .iter()
        .zip(&rust_reports)
        .enumerate()
    {
        let step_label = format!("{label} action {step}");
        compare_state_machine_advance(
            cpp_state_machine,
            rust_state_machine,
            *advanced,
            &step_label,
        );
        for data_bind_index in data_bind_indices {
            compare_state_machine_asset_binding(
                cpp_state_machine,
                rust_state_machine,
                *data_bind_index,
                &step_label,
            );
        }
    }
    compare_cpp_runtime_update(&cpp, &rust, &report, label);
}

