#[test]
fn state_machine_artboard_comparand_conditions_match_cpp_probe() {
    let Some(probe) = probe_path() else {
        eprintln!("skipping C++ runtime comparison; set RIVE_CPP_PROBE to enable");
        return;
    };

    struct Case<'a> {
        label: &'a str,
        bytes: Vec<u8>,
        artboard_size: Option<(f32, f32)>,
    }

    for case in [
        Case {
            label: "synthetic/runtime_state_machine_artboard_width_condition_cpp.riv",
            bytes: synthetic_state_machine_artboard_number_condition(8274, 0, 150.0),
            artboard_size: None,
        },
        Case {
            label: "synthetic/runtime_state_machine_artboard_height_condition_cpp.riv",
            bytes: synthetic_state_machine_artboard_number_condition(8275, 1, 75.0),
            artboard_size: None,
        },
        Case {
            label: "synthetic/runtime_state_machine_artboard_ratio_condition_cpp.riv",
            bytes: synthetic_state_machine_artboard_number_condition(8276, 2, 1.5),
            artboard_size: None,
        },
        Case {
            label: "synthetic/runtime_state_machine_artboard_false_condition_cpp.riv",
            bytes: synthetic_state_machine_artboard_number_condition(8277, 0, 250.0),
            artboard_size: None,
        },
        Case {
            label: "synthetic/runtime_state_machine_artboard_mutated_width_condition_cpp.riv",
            bytes: synthetic_state_machine_artboard_number_condition(8356, 0, 250.0),
            artboard_size: Some((300.0, 100.0)),
        },
    ] {
        let mut args = Vec::new();
        if let Some((width, height)) = case.artboard_size {
            args.extend([
                "--runtime-set-artboard-size".to_owned(),
                width.to_string(),
                height.to_string(),
            ]);
        }
        args.extend([
            "--runtime-advance-state-machine".to_owned(),
            "0".to_owned(),
            "0".to_owned(),
            "--runtime-advance-state-machine".to_owned(),
            "0".to_owned(),
            "0".to_owned(),
            "--runtime-advance-state-machine".to_owned(),
            "0".to_owned(),
            "1".to_owned(),
        ]);

        let cpp = read_cpp_probe_bytes_with_args(&probe, case.label, &case.bytes, &args);
        let (_, mut rust) = read_rust_instance_from_bytes(&case.bytes, case.label);
        let mut state_machine = rust
            .state_machine_instance(0)
            .unwrap_or_else(|| panic!("missing Rust state-machine instance for {}", case.label));
        if let Some((width, height)) = case.artboard_size {
            assert!(
                rust.set_artboard_dimensions(width, height),
                "{} failed to mutate Rust artboard dimensions",
                case.label
            );
        }

        let mut rust_reports = Vec::new();
        rust_reports.push((
            rust.advance_state_machine_instance(&mut state_machine, 0.0),
            state_machine.clone(),
        ));
        rust_reports.push((
            rust.advance_state_machine_instance(&mut state_machine, 0.0),
            state_machine.clone(),
        ));
        rust_reports.push((
            rust.advance_state_machine_instance(&mut state_machine, 1.0),
            state_machine.clone(),
        ));
        let report = rust.update_components();

        let cpp_artboard = cpp
            .artboards
            .first()
            .unwrap_or_else(|| panic!("missing C++ artboard for {}", case.label));
        assert_eq!(
            cpp_artboard.runtime_state_machine_advances.len(),
            rust_reports.len(),
            "{} state-machine report count mismatch",
            case.label
        );
        for (cpp_state_machine, (advanced, rust_state_machine)) in cpp_artboard
            .runtime_state_machine_advances
            .iter()
            .zip(&rust_reports)
        {
            compare_state_machine_advance(
                cpp_state_machine,
                rust_state_machine,
                *advanced,
                case.label,
            );
        }
        compare_cpp_runtime_update(&cpp, &rust, &report, case.label);
    }
}

#[test]
fn state_machine_component_literal_conditions_match_cpp_probe() {
    let Some(probe) = probe_path() else {
        eprintln!("skipping C++ runtime comparison; set RIVE_CPP_PROBE to enable");
        return;
    };

    let node_x_key = property_key_for_name("Node", "x");
    let artboard_width_key = property_key_for_name("Artboard", "width");

    for (label, bytes, mutated_x) in [
        (
            "synthetic/runtime_state_machine_component_number_static_true_cpp.riv",
            synthetic_state_machine_component_number_condition(8316, 1, node_x_key, 5, 1.0),
            None,
        ),
        (
            "synthetic/runtime_state_machine_component_number_static_false_cpp.riv",
            synthetic_state_machine_component_number_condition(8317, 1, node_x_key, 5, 10.0),
            None,
        ),
        (
            "synthetic/runtime_state_machine_component_number_mutated_true_cpp.riv",
            synthetic_state_machine_component_number_condition(8318, 1, node_x_key, 5, 10.0),
            Some(12.0),
        ),
        (
            "synthetic/runtime_state_machine_component_number_missing_default_cpp.riv",
            synthetic_state_machine_component_number_condition(8319, 99, node_x_key, 5, -1.0),
            None,
        ),
        (
            "synthetic/runtime_state_machine_component_number_unsupported_default_cpp.riv",
            synthetic_state_machine_component_number_condition(8320, 1, artboard_width_key, 0, 0.0),
            None,
        ),
    ] {
        let mut args = Vec::new();
        if let Some(value) = mutated_x {
            args.extend([
                "--runtime-set-double".to_owned(),
                "1".to_owned(),
                node_x_key.to_string(),
                value.to_string(),
            ]);
        }
        args.extend([
            "--runtime-advance-state-machine".to_owned(),
            "0".to_owned(),
            "0".to_owned(),
            "--runtime-advance-state-machine".to_owned(),
            "0".to_owned(),
            "0".to_owned(),
        ]);

        let cpp = read_cpp_probe_bytes_with_args(&probe, label, &bytes, &args);
        let (_, mut rust) = read_rust_instance_from_bytes(&bytes, label);
        if let Some(value) = mutated_x {
            assert!(
                rust.set_transform_property(1, TransformProperty::X, value),
                "{label} failed to mutate component x"
            );
        }
        let mut state_machine = rust
            .state_machine_instance(0)
            .unwrap_or_else(|| panic!("missing Rust state-machine instance for {label}"));

        let mut rust_reports = Vec::new();
        rust_reports.push((
            rust.advance_state_machine_instance(&mut state_machine, 0.0),
            state_machine.clone(),
        ));
        rust_reports.push((
            rust.advance_state_machine_instance(&mut state_machine, 0.0),
            state_machine.clone(),
        ));
        let report = rust.update_components();

        let cpp_artboard = cpp
            .artboards
            .first()
            .unwrap_or_else(|| panic!("missing C++ artboard for {label}"));
        assert_eq!(
            cpp_artboard.runtime_state_machine_advances.len(),
            rust_reports.len(),
            "{label} state-machine report count mismatch"
        );
        for (cpp_state_machine, (advanced, rust_state_machine)) in cpp_artboard
            .runtime_state_machine_advances
            .iter()
            .zip(&rust_reports)
        {
            compare_state_machine_advance(cpp_state_machine, rust_state_machine, *advanced, label);
        }
        compare_cpp_runtime_update(&cpp, &rust, &report, label);
    }
}

