#[derive(Debug, Deserialize)]
struct CppPathCommand {
    verb: String,
    points: Vec<[f32; 2]>,
}

impl CppPathCommand {
    fn path_command(&self) -> RuntimePathCommand {
        match self.verb.as_str() {
            "move" => RuntimePathCommand::Move {
                x: self.points[0][0],
                y: self.points[0][1],
            },
            "line" => RuntimePathCommand::Line {
                x: self.points[0][0],
                y: self.points[0][1],
            },
            "cubic" => RuntimePathCommand::Cubic {
                x1: self.points[0][0],
                y1: self.points[0][1],
                x2: self.points[1][0],
                y2: self.points[1][1],
                x3: self.points[2][0],
                y3: self.points[2][1],
            },
            "close" => RuntimePathCommand::Close,
            other => panic!("unexpected C++ raw path verb {other}"),
        }
    }
}

